import React, { useState } from 'react';
import Sidebar from './components/layout/Sidebar';
import Header from './components/layout/Header';
import Dashboard from './components/dashboard/Dashboard';

function App() {
  // 'Kyle의 코멘트' 상태 관리 (true: 켬, false: 끔)
  const [showInsights, setShowInsights] = useState(false);

  const toggleInsights = () => {
    setShowInsights(!showInsights);
  };

  return (
    <div className={`flex h-screen overflow-hidden ${showInsights ? 'insight-active' : ''}`}>
      {/* 1. 사이드바 */}
      <Sidebar />

      {/* 오른쪽 메인 영역 */}
      <div className="flex-1 flex flex-col h-screen overflow-hidden">
        {/* 2. 상단 헤더 (코멘트 토글 버튼 포함) */}
        <Header onToggleInsights={toggleInsights} showInsights={showInsights} />

        {/* 3. 대시보드 콘텐츠 (본문) */}
        <main className="flex-1 overflow-y-auto p-4 md:p-8 scroll-smooth">
          <Dashboard showInsights={showInsights} />
        </main>
      </div>
    </div>
  );
}

export default App;
